code = """import json
import duckdb

nyse_path = locals()['var_functions.query_db:74']
with open(nyse_path, 'r') as f:
    nyse_data = json.load(f)

symbol_to_name = {item['Symbol']: item['name'] for item in nyse_data}

conn = duckdb.connect()
conn.execute("ATTACH 'stocktrade_database' AS trade_db")

qualified_stocks = []
processed = 0

for symbol in symbol_to_name.keys():
    try:
        table_name = 'trade_db."' + symbol + '"'
        query = "SELECT SUM(CASE WHEN Close > Open THEN 1 ELSE 0 END) as up_days, SUM(CASE WHEN Close < Open THEN 1 ELSE 0 END) as down_days FROM " + table_name + " WHERE Date >= '2017-01-01' AND Date <= '2017-12-31'"
        row = conn.execute(query).fetchone()
        if row and row[0] is not None:
            up_days = int(row[0])
            down_days = int(row[1]) if row[1] else 0
            if up_days > down_days:
                diff = up_days - down_days
                qualified_stocks.append({'symbol': symbol, 'name': symbol_to_name[symbol], 'up': up_days, 'down': down_days, 'diff': diff})
        processed += 1
        if processed % 50 == 0:
            print("Processed", processed, "stocks, found", len(qualified_stocks), "qualified")
    except Exception as e:
        pass

conn.close()
qualified_stocks.sort(key=lambda x: x['diff'], reverse=True)

print('__RESULT__')
print(json.dumps(qualified_stocks[:5]))"""

